 49→    private fun visitClassDeclaration(
 50→        node: ASTNode,
 51→        autoCorrect: Boolean,
 52→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 53→    ) {
 54→        // No white space expected between class name and parameter list
 55→        //     class Bar <T>
 56→        node
 57→            .prevSibling { true }
 58→            ?.takeIf { it.elementType == WHITE_SPACE }
 59→            ?.let { noWhitespaceExpected(it, autoCorrect, emit) }
 60→
 61→        // No white space expected between parameter type list and the constructor except when followed by compound
 62→        // constructor
 63→        //     class Bar<T> (...)
 64→        node
 65→            .nextSibling { true }
 66→            ?.takeIf { it.elementType == WHITE_SPACE && it.nextCodeSibling()?.elementType == PRIMARY_CONSTRUCTOR }
 67→            ?.let { whiteSpace ->
 68→                if (whiteSpace.nextCodeSibling()?.findChildByType(CONSTRUCTOR_KEYWORD) != null) {
 69→                    // Single space expect before (modifier list of) constructor
 70→                    //    class Bar<T> constructor(...)
 71→                    //    class Bar<T> actual constructor(...)
 72→                    //    class Bar<T> @SomeAnnotation constructor(...)
 73→                    singleSpaceExpected(whiteSpace, autoCorrect, emit)
 74→                } else {
 75→                    noWhitespaceExpected(whiteSpace, autoCorrect, emit)
 76→                }
 77→            }
 78→
 79→        // No white space expected between parameter type list and class body when constructor is missing
 80→        //    class Bar<T> {
 81→        node
 82→            .nextSibling { true }
 83→            ?.takeIf { it.elementType == WHITE_SPACE && it.nextCodeSibling()?.elementType == CLASS_BODY }
 84→            ?.let { singleSpaceExpected(it, autoCorrect, emit) }
 85→    }
