227→/**
228→ * Updates or inserts a new whitespace element with [text] before the given node. If the node itself is a whitespace
229→ * then its contents is replaced with [text]. If the node is a (nested) composite element, the whitespace element is
230→ * added after the previous leaf node.
231→ */
232→public fun ASTNode.upsertWhitespaceBeforeMe(text: String) {
233→    if (this is LeafElement) {
234→        if (this.elementType == WHITE_SPACE) {
235→            return replaceWhitespaceWith(text)
236→        }
237→        val previous = treePrev ?: prevLeaf()
238→        if (previous != null && previous.elementType == WHITE_SPACE) {
239→            previous.replaceWhitespaceWith(text)
240→        } else {
241→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
242→                (psi as LeafElement).rawInsertBeforeMe(psiWhiteSpace)
243→            }
244→        }
245→    } else {
246→        val prevLeaf =
247→            requireNotNull(prevLeaf()) {
248→                "Can not upsert a whitespace if the first node is a non-leaf node"
249→            }
250→        prevLeaf.upsertWhitespaceAfterMe(text)
251→    }
252→}
253→
254→private fun ASTNode.replaceWhitespaceWith(text: String) {
255→    require(this.elementType == WHITE_SPACE)
256→    if (this.text != text) {
257→        (this.psi as LeafElement).rawReplaceWithText(text)
258→    }
259→}
260→
261→/**
262→ * Updates or inserts a new whitespace element with [text] after the given node. If the node itself is a whitespace
263→ * then its contents is replaced with [text]. If the node is a (nested) composite element, the whitespace element is
264→ * added after the last child leaf.
265→ */
266→public fun ASTNode.upsertWhitespaceAfterMe(text: String) {
267→    if (this is LeafElement) {
268→        if (this.elementType == WHITE_SPACE) {
269→            return replaceWhitespaceWith(text)
270→        }
271→        val next = treeNext ?: nextLeaf()
272→        if (next != null && next.elementType == WHITE_SPACE) {
273→            next.replaceWhitespaceWith(text)
274→        } else {
275→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
276→                (psi as LeafElement).rawInsertAfterMe(psiWhiteSpace)
277→            }
278→        }
279→    } else {
280→        lastChildLeafOrSelf().upsertWhitespaceAfterMe(text)
281→    }
282→}
