310→/**
311→ *  Print content of a node and the element type of the node, its parent and its direct children. Utility is meant to
312→ *  be used during development only. Please do not remove.
313→ */
314→@Suppress("unused")
315→public fun ASTNode.logStructure(): ASTNode =
316→    also {
317→        println("Processing ${text.replaceTabAndNewline()} : Type $elementType with parent ${treeParent?.elementType} ")
318→        children()
319→            .toList()
320→            .map {
321→                println("  ${it.text.replaceTabAndNewline()} : Type ${it.elementType}")
322→            }
