  3→import com.pinterest.ktlint.rule.engine.core.api.ElementType.CLASS
  4→import com.pinterest.ktlint.rule.engine.core.api.ElementType.CLASS_BODY
  5→import com.pinterest.ktlint.rule.engine.core.api.ElementType.CONSTRUCTOR_KEYWORD
  6→import com.pinterest.ktlint.rule.engine.core.api.ElementType.EQ
  7→import com.pinterest.ktlint.rule.engine.core.api.ElementType.FUN
  8→import com.pinterest.ktlint.rule.engine.core.api.ElementType.GT
  9→import com.pinterest.ktlint.rule.engine.core.api.ElementType.LT
 10→import com.pinterest.ktlint.rule.engine.core.api.ElementType.PRIMARY_CONSTRUCTOR
 11→import com.pinterest.ktlint.rule.engine.core.api.ElementType.TYPEALIAS
 12→import com.pinterest.ktlint.rule.engine.core.api.ElementType.TYPE_PARAMETER_LIST
 13→import com.pinterest.ktlint.rule.engine.core.api.ElementType.WHITE_SPACE
 14→import com.pinterest.ktlint.rule.engine.core.api.Rule
 15→import com.pinterest.ktlint.rule.engine.core.api.RuleId
 16→import com.pinterest.ktlint.rule.engine.core.api.nextCodeSibling
 17→import com.pinterest.ktlint.rule.engine.core.api.nextLeaf
 18→import com.pinterest.ktlint.rule.engine.core.api.nextSibling
 19→import com.pinterest.ktlint.rule.engine.core.api.prevLeaf
 20→import com.pinterest.ktlint.rule.engine.core.api.prevSibling
 21→import com.pinterest.ktlint.rule.engine.core.api.upsertWhitespaceBeforeMe
 22→import com.pinterest.ktlint.ruleset.standard.StandardRule
 23→import org.jetbrains.kotlin.com.intellij.lang.ASTNode
 24→import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafPsiElement
 25→
 26→/**
 27→ * Lints and formats the spacing before and after the angle brackets of a type parameter list.
 28→ */
 29→public class TypeParameterListSpacingRule :
 30→    StandardRule("type-parameter-list-spacing"),
 31→    Rule.Experimental {
 32→    override fun beforeVisitChildNodes(
 33→        node: ASTNode,
 34→        autoCorrect: Boolean,
 35→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 36→    ) {
 37→        if (node.elementType != TYPE_PARAMETER_LIST) {
 38→            return
 39→        }
 40→
 41→        when (node.treeParent.elementType) {
 42→            CLASS -> visitClassDeclaration(node, autoCorrect, emit)
 43→            TYPEALIAS -> visitTypeAliasDeclaration(node, autoCorrect, emit)
 44→            FUN -> visitFunctionDeclaration(node, autoCorrect, emit)
 45→        }
 46→        visitInsideTypeParameterList(node, autoCorrect, emit)
 47→    }
 48→
 49→    private fun visitClassDeclaration(
 50→        node: ASTNode,
 51→        autoCorrect: Boolean,
 52→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 53→    ) {
 54→        // No white space expected between class name and parameter list
 55→        //     class Bar <T>
 56→        node
 57→            .prevSibling { true }
 58→            ?.takeIf { it.elementType == WHITE_SPACE }
 59→            ?.let { noWhitespaceExpected(it, autoCorrect, emit) }
 60→
 61→        // No white space expected between parameter type list and the constructor except when followed by compound
 62→        // constructor
 63→        //     class Bar<T> (...)
 64→        node
 65→            .nextSibling { true }
 66→            ?.takeIf { it.elementType == WHITE_SPACE && it.nextCodeSibling()?.elementType == PRIMARY_CONSTRUCTOR }
 67→            ?.let { whiteSpace ->
 68→                if (whiteSpace.nextCodeSibling()?.findChildByType(CONSTRUCTOR_KEYWORD) != null) {
 69→                    // Single space expect before (modifier list of) constructor
 70→                    //    class Bar<T> constructor(...)
 71→                    //    class Bar<T> actual constructor(...)
 72→                    //    class Bar<T> @SomeAnnotation constructor(...)
 73→                    singleSpaceExpected(whiteSpace, autoCorrect, emit)
 74→                } else {
 75→                    noWhitespaceExpected(whiteSpace, autoCorrect, emit)
 76→                }
 77→            }
 78→
 79→        // No white space expected between parameter type list and class body when constructor is missing
 80→        //    class Bar<T> {
 81→        node
 82→            .nextSibling { true }
 83→            ?.takeIf { it.elementType == WHITE_SPACE && it.nextCodeSibling()?.elementType == CLASS_BODY }
 84→            ?.let { singleSpaceExpected(it, autoCorrect, emit) }
 85→    }
 86→
 87→    private fun visitTypeAliasDeclaration(
 88→        node: ASTNode,
 89→        autoCorrect: Boolean,
 90→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 91→    ) {
 92→        // No white space expected between typealias keyword name and parameter list
 93→        //     typealias Bar <T>
 94→        node
 95→            .prevSibling { true }
 96→            ?.takeIf { it.elementType == WHITE_SPACE }
 97→            ?.let { noWhitespaceExpected(it, autoCorrect, emit) }
 98→
 99→        // No white space expected between parameter type list and equals sign
100→        //    typealias Bar<T> = ...
101→        node
102→            .nextSibling { true }
103→            ?.takeIf { it.elementType == WHITE_SPACE && it.nextCodeSibling()?.elementType == EQ }
104→            ?.let { singleSpaceExpected(it, autoCorrect, emit) }
105→    }
106→
107→    private fun visitFunctionDeclaration(
108→        node: ASTNode,
109→        autoCorrect: Boolean,
110→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
111→    ) {
112→        // Single space expected before type parameter list of function
113→        //    fun<T> foo(...)
114→        node
115→            .prevLeaf(includeEmpty = true)
116→            ?.let { prevLeaf ->
117→                if (prevLeaf.elementType == WHITE_SPACE) {
118→                    singleSpaceExpected(prevLeaf, autoCorrect, emit)
119→                } else {
120→                    singleSpaceExpected(node.firstChildNode, autoCorrect, emit)
121→                }
122→            }
123→
124→        // Single space expected after type parameter list of function
125→        //   fun <T>foo(...)
126→        //   fun <T>List<T>foo(...)
127→        node
128→            .lastChildNode
129→            .nextLeaf(includeEmpty = true)
130→            ?.let { nextSibling ->
131→                singleSpaceExpected(nextSibling, autoCorrect, emit)
132→            }
133→    }
134→
135→    private fun visitInsideTypeParameterList(
136→        node: ASTNode,
137→        autoCorrect: Boolean,
138→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
139→    ) {
140→        node
141→            .findChildByType(LT)
142→            ?.nextSibling { true }
143→            ?.takeIf { it.elementType == WHITE_SPACE }
144→            ?.let { noWhitespaceExpected(it, autoCorrect, emit) }
145→
146→        node
147→            .findChildByType(GT)
148→            ?.prevSibling { true }
149→            ?.takeIf { it.elementType == WHITE_SPACE }
150→            ?.let { noWhitespaceExpected(it, autoCorrect, emit) }
151→    }
152→
153→    private fun noWhitespaceExpected(
154→        node: ASTNode,
155→        autoCorrect: Boolean,
156→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
157→    ) {
158→        if (node.text != "") {
159→            emit(
160→                node.startOffset,
161→                "No whitespace expected at this position",
162→                true,
163→            )
164→            if (autoCorrect) {
165→                node.treeParent.removeChild(node)
166→            }
167→        }
168→    }
169→
170→    private fun singleSpaceExpected(
171→        node: ASTNode,
172→        autoCorrect: Boolean,
173→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
174→    ) {
175→        when {
176→            node.text == " " -> Unit
177→            node.textContains('\n') -> {
178→                emit(
179→                    node.startOffset,
180→                    "Expected a single space instead of newline",
181→                    true,
182→                )
183→                if (autoCorrect) {
184→                    (node as LeafPsiElement).rawReplaceWithText(" ")
185→                }
186→            }
187→            else -> {
188→                emit(
189→                    node.startOffset,
190→                    "Expected a single space",
191→                    true,
192→                )
193→                if (autoCorrect) {
194→                    node.upsertWhitespaceBeforeMe(" ")
195→                }
196→            }
197→        }
198→    }
199→}
