299→public fun ASTNode.lineIndent(): String {
300→    var leaf = this.prevLeaf()
301→    while (leaf != null) {
302→        if (leaf.elementType == WHITE_SPACE && leaf.textContains('\n')) {
303→            return leaf.text.substring(leaf.text.lastIndexOf('\n') + 1)
304→        }
305→        leaf = leaf.prevLeaf()
306→    }
307→    return ""
308→}
